const path = require('path');

const PROBLEMS_FILE = path.resolve(__dirname, '../../data/problems.json');

function loadProblems() {
  const raw = fs.readFileSync(PROBLEMS_FILE, 'utf8');
  return JSON.parse(raw);
}

/**
 * Get problems list with filtering, paging, sorting, and metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - difficulty filter, e.g. 'Easy', 'Medium', 'Hard'
 * @param {boolean} [options.includeComponents] - whether to include sorted componentLanguages
 * @param {number} [options.limit=50] - max number of results to return, capped at 50
 * @returns {Object} result with problems array and metadata
 */
function getProblemsList({ difficulty, includeComponents = false, limit = 50 } = {}) {
  const problems = loadProblems();

  // Normalize limit and cap at 50
  const appliedLimit = Math.min(limit || 50, 50);

  // Filter by difficulty if provided
  let filtered = problems;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Sort by roundId ascending, then by problemId ascending for deterministic ordering
  filtered.sort((a, b) => {
    if (a.roundId !== b.roundId) return a.roundId - b.roundId;
    if (a.problemId !== b.problemId) return a.problemId - b.problemId;
    return 0;
  });

  // Apply limit
  const limited = filtered.slice(0, appliedLimit);

  // Prepare difficulty breakdown
  const difficultyBreakdown = {};
  for (const p of problems) {
    difficultyBreakdown[p.difficulty] = (difficultyBreakdown[p.difficulty] || 0) + 1;
  }

  // If includeComponents, add sorted componentLanguages array to each problem
  if (includeComponents) {
    for (const p of limited) {
      if (Array.isArray(p.componentLanguages)) {
        p.componentLanguages = [...p.componentLanguages].sort();
      } else {
        p.componentLanguages = [];
      }
    }
  }

  return {
    problems: limited,
    totalProblems: problems.length,
    filteredCount: filtered.length,
    appliedLimit,
    difficultyBreakdown
  };
}

module.exports = {
  getProblemsList
};
